# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using UnityEngine.UI;

public class PlayerStats : MonoBehaviour
{
    public int playerHealth = 100;
    public int maxPlayerHealth = 100;
    public int currency = 0;

    public int damage = 10;
    public int damageMultiplier = 1;

    public void TakeDamage(int incomingDamage)
    {
        int finalDamage = CalculateDamageTaken(incomingDamage);
        playerHealth -= finalDamage;
        if (playerHealth < 0) playerHealth = 0;
    }

    public int CalculateDamageTaken(int incomingDamage)
    {
        return Mathf.Max(0, incomingDamage);
    }

    public void AddCurrency(int amount)
    {
        currency += Mathf.Max(0, amount);
    }

    public bool CanAfford(int price)
    {
        return currency >= price;
    }

    public bool BuyItem(int price, int healthRestore, int damageIncrease)
    {
        if (!CanAfford(price))
            return false;

        currency -= price;
        if (healthRestore > 0)
        {
            playerHealth += healthRestore;
            if (playerHealth > maxPlayerHealth) playerHealth = maxPlayerHealth;
        }

        if (damageIncrease > 0)
        {
            damage += damageIncrease;
        }

        return true;
    }

    public int CalculatePrice(int basePrice, int priceMultiplier)
    {
        return Mathf.Max(0, basePrice * Mathf.Max(1, priceMultiplier));
    }

    public int CalculateDamage(int baseDamage)
    {
        return Mathf.Max(0, baseDamage * Mathf.Max(1, damageMultiplier));
    }
}

public class ShopItem : MonoBehaviour
{
    public string itemName;
    public int basePrice = 100;
    public int priceMultiplier = 1;
    public int healthRestore = 0;
    public int damageIncrease = 0;

    public Text priceText;
    public Button buyButton;

    public int CurrentPrice(PlayerStats playerStats)
    {
        return playerStats != null ? playerStats.CalculatePrice(basePrice, priceMultiplier) : basePrice;
    }

    public void RefreshUI(PlayerStats playerStats)
    {
        if (priceText != null)
            priceText.text = CurrentPrice(playerStats).ToString();

        if (buyButton != null)
            buyButton.interactable = playerStats != null && playerStats.CanAfford(CurrentPrice(playerStats));
    }

    public void Buy(PlayerStats playerStats)
    {
        if (playerStats == null)
            return;

        int price = CurrentPrice(playerStats);
        playerStats.BuyItem(price, healthRestore, damageIncrease);
        RefreshUI(playerStats);
    }
}

public class DamageDealer : MonoBehaviour
{
    public int baseDamage = 10;

    public void DealDamage(PlayerStats target)
    {
        if (target == null)
            return;

        int finalDamage = CalculateDamage();
        target.TakeDamage(finalDamage);
    }

    public int CalculateDamage()
    {
        return Mathf.Max(0, baseDamage);
    }
}

public class CurrencyReward : MonoBehaviour
{
    public int rewardAmount = 50;

    public void GrantReward(PlayerStats playerStats)
    {
        if (playerStats == null)
            return;

        playerStats.AddCurrency(rewardAmount);
    }
}

public class SimpleGameManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public ShopItem[] shopItems;

    private void Start()
    {
        RefreshShop();
    }

    private void Update()
    {
        if (Input.GetKeyDown(KeyCode.H) && playerStats != null)
        {
            playerStats.TakeDamage(10);
        }

        if (Input.GetKeyDown(KeyCode.C) && playerStats != null)
        {
            playerStats.AddCurrency(100);
        }

        if (Input.GetKeyDown(KeyCode.R) && playerStats != null)
        {
            playerStats.playerHealth = playerStats.maxPlayerHealth;
        }
    }

    public void RefreshShop()
    {
        if (shopItems == null)
            return;

        for (int i = 0; i < shopItems.Length; i++)
        {
            if (shopItems[i] != null)
                shopItems[i].RefreshUI(playerStats);
        }
    }
}